import React, { useState, useEffect } from 'react';
import EventDetails from './EventDetails';
import BookingForm from './BookingForm';

function App() {

  // Tracks available tickets — fetched from backend
  const [availableTickets, setAvailableTickets] = useState(null);

  // Stores booking confirmation data after a successful booking
  const [bookingConfirmation, setBookingConfirmation] = useState(null);

  // Error if backend is unreachable
  const [fetchError, setFetchError] = useState('');

  // Fetch available tickets from backend when page loads
  useEffect(() => {
    fetchAvailableTickets();
  }, []);

  async function fetchAvailableTickets() {
    try {
      const response = await fetch('http://localhost:8080/tickets');
      const data = await response.json();
      setAvailableTickets(data.availableTickets);
      setFetchError('');
    } catch (error) {
      setFetchError('Could not connect to backend. Please start the Spring Boot server.');
    }
  }

  // Called by BookingForm when booking is successful
  function handleBookingSuccess(data) {
    // Update available tickets shown in EventDetails
    setAvailableTickets(data.remainingTickets);
    // Show confirmation screen
    setBookingConfirmation(data);
  }

  // Called when user clicks "Book Another Ticket"
  function handleBookAnother() {
    setBookingConfirmation(null);
  }

  return (
    <div>
      {/* Page Header */}
      <div className="page-title">
        Tech Fest 2026 - Ticket Booking System
      </div>

      <div className="main-container">

        {/* Show fetch error if backend is down */}
        {fetchError && (
          <div className="error-message">{fetchError}</div>
        )}

        {/* Always show event details at top */}
        <EventDetails availableTickets={availableTickets !== null ? availableTickets : 'Loading...'} />

        {/* Conditional rendering: show confirmation OR booking form */}
        {bookingConfirmation ? (
          // BOOKING CONFIRMATION
          <div className="confirmation-box">
            <h2>Booking Confirmed!</h2>
            <p>Name: <span>{bookingConfirmation.name}</span></p>
            <p>Event: <span>{bookingConfirmation.eventName}</span></p>
            <p>Tickets Booked: <span>{bookingConfirmation.ticketsBooked}</span></p>
            <p>Total Amount: <span>&#8377;{bookingConfirmation.totalAmount}</span></p>
            <button className="btn-book-again" onClick={handleBookAnother}>
              Book Another Ticket
            </button>
          </div>
        ) : (
          // BOOKING FORM
          <BookingForm
            availableTickets={availableTickets || 0}
            onBookingSuccess={handleBookingSuccess}
          />
        )}

      </div>
    </div>
  );
}

export default App;
